export class EventBus {
  private handlers: Map<EventType, EventHandler[]> = new Map();
  private eventLog: AppEvent[] = [];
  private queue: Array<{ event: AppEvent; resolve: () => void; reject: (err: unknown) => void }> = [];
  private processing = false;

  /**
   * Subscribe to events of a given type.
   */
  on<T extends AppEvent>(
    eventType: T['type'],
    handler: EventHandler<T>,
  ): () => void {
    const handlers = this.handlers.get(eventType) ?? [];
    handlers.push(handler as EventHandler);
    this.handlers.set(eventType, handlers);

    // Return unsubscribe function
    return () => {
      const current = this.handlers.get(eventType) ?? [];
      const index = current.indexOf(handler as EventHandler);
      if (index >= 0) {
        current.splice(index, 1);
      }
    };
  }

  /**
   * Emit an event to all registered handlers.
   * Events are queued and processed sequentially to guarantee delivery order.
   */
  async emit<T extends AppEvent>(event: T): Promise<void> {
    return new Promise<void>((resolve, reject) => {
      this.queue.push({ event, resolve, reject });
      this.processQueue();
    });
  }

  private async processQueue(): Promise<void> {
    if (this.processing) return;
    this.processing = true;

    while (this.queue.length > 0) {
      const item = this.queue.shift()!;
      try {
        this.eventLog.push(item.event);
        const handlers = this.handlers.get(item.event.type) ?? [];
        for (const handler of handlers) {
          await handler(item.event);
        }
        item.resolve();
      } catch (err) {
        item.reject(err);
      }
    }

    this.processing = false;
  }

